  ('promotion-8b44517b-moex-00017', 'promotion-8b44517b', 'promotion-8b44517b-moex-114-3082b5f1', 'sub-promotion-8b44517b-04', NULL, 'single_choice', '依司法院大法官解釋意旨，關於行政機關之判斷餘地，司法審查之範圍不包括下列何者？', '["行政機關之判斷，是否出於錯誤事實認定或不完全資訊", "法律概念涉及事實關係時，其涵攝有無明顯錯誤", "作成判斷之行政機關，其組織是否合法且有判斷之權限", "行政機關所為公務人員考績處分，是否符合其績效表現"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:44+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "107", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('promotion-8b44517b-moex-00018', 'promotion-8b44517b', 'promotion-8b44517b-moex-114-3082b5f1', 'sub-promotion-8b44517b-04', NULL, 'single_choice', '關於行政法人之敘述，下列何者正確？', '["行政法人為行政機關，受其設置上級機關之指揮監督", "行政法人之人事、財政自主空間較大，完全排除國家人事、預算、會計及審計法規之適用", "地方自治團體得以自治條例設立地方行政法人", "行政法人依其人事管理規章所進用之人員，為公務人員 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:44+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "107", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "勞工行政"}'::jsonb, NULL),
